sql:
SELECT promo_id, promo_type, file_path, upload_date, description, platform, created_at, updated_at
FROM promotional_materials
WHERE episode_id = 1;

SELECT DISTINCT directors.name
FROM directors
JOIN series ON directors.director_id = series.producer_id;

SELECT promo_type, COUNT(*) as total_promos
FROM promotional_materials
GROUP BY promo_type;

external_knowledge:
Average rating > 8: Represents excellence;
Total views > 1,000,000: Equivalent to a bustling city's population;
Total feedbacks > 500: Analogous to grains of sand on a beach.

- 'Sailed into the harbor of high acclaim' is a metaphor for achieving or receiving high ratings;
- 'Whispers of praise or critique' refers to the comments left by users;
- 'Rating stones' are a metaphor for user ratings.

sql:
SELECT series_id, title
FROM series
WHERE budget = (SELECT MAX(budget) FROM series);

SELECT series_id, title, genre, premiere_date
FROM series
WHERE producer_id = (SELECT user_id FROM users WHERE username = 'alice.j');
